import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Mock any external dependencies the hook might use
vi.mock('../api/notes', () => ({
  createNote: vi.fn(),
  fetchNote: vi.fn(),
}));

// Import the hook after mocking
import { useNoteEditor } from '../src/composables/useNoteEditor';
import { createNote, fetchNote } from '../api/notes';

describe('useNoteEditor', () => {
  const onNoteCreated = vi.fn();

  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should handle happy path with valid selectedNoteId and onNoteCreated', async () => {
    // Arrange
    const noteData = { id: '123', title: 'Test', content: 'Hello' };
    (fetchNote as any).mockResolvedValueOnce(noteData);
    const { note, loadNote, saveNote } = useNoteEditor({
      selectedNoteId: '123',
      onNoteCreated,
    });

    // Act
    await loadNote();
    await saveNote({ title: 'Updated', content: 'World' });

    // Assert
    expect(note.value).toEqual(noteData);
    expect(createNote).toHaveBeenCalledTimes(1);
    expect(onNoteCreated).toHaveBeenCalledWith(expect.objectContaining({ id: '123' }));
  });

  it('should handle edge case when selectedNoteId is an empty string (treated as new note)', async () => {
    // Arrange
    (createNote as any).mockResolvedValueOnce({ id: 'new-id', title: '', content: '' });
    const { note, loadNote, saveNote } = useNoteEditor({
      selectedNoteId: '',
      onNoteCreated,
    });

    // Act
    await loadNote(); // should not attempt fetch
    await saveNote({ title: 'New', content: 'Note' });

    // Assert
    expect(fetchNote).not.toHaveBeenCalled();
    expect(createNote).toHaveBeenCalledWith({ title: 'New', content: 'Note' });
    expect(note.value?.id).toBe('new-id');
    expect(onNoteCreated).toHaveBeenCalledWith(expect.objectContaining({ id: 'new-id' }));
  });

  it('should handle null/undefined/empty inputs gracefully', async () => {
    // Arrange
    const { note, loadNote, saveNote } = useNoteEditor({
      selectedNoteId: undefined,
      onNoteCreated: undefined as any,
    });

    // Act
    await loadNote(); // should be a no‑op
    await saveNote({ title: '', content: '' });

    // Assert
    expect(fetchNote).not.toHaveBeenCalled();
    // createNote may still be called for a new empty note
    expect(createNote).toHaveBeenCalledWith({ title: '', content: '' });
    expect(note.value).toBeDefined();
  });
});